// Parse rows from N8N configs sheet.
// Looks for rows where `field` matches "<Group> smartsheet ID" (case-insensitive regex).
// Emits one item per category_group with { category_group, categories: string[] }
// Categories come from the `categories_list` column (comma-separated), NOT from the smartsheet ID value.
const rows = $input.all().map(i => i.json);
const FIELD_RE = /^(.+?)\s+smartsheet\s+id$/i;

const out = [];
for (const row of rows) {
  const fieldVal = String(row.field || row.Field || '').trim();
  const match = fieldVal.match(FIELD_RE);
  if (!match) continue;
  const category_group = match[1].trim().toLowerCase();
  if (!category_group) continue;
  const raw = String(row.categories_list ?? row['Categories List'] ?? row['categories list'] ?? '').trim();
  const categories = raw.split(',').map(s => s.trim()).filter(Boolean);
  if (categories.length === 0) continue;
  out.push({ json: { category_group, categories } });
}

if (out.length === 0) {
  throw new Error('No category groups found in N8N configs sheet. Check field names and categories_list column.');
}
return out;

// Emit one item per category_group from Parse Config output.
// Each item: { category_group, categories }
const configItems = $('Parse Config').all();
return configItems.map(i => ({ json: { category_group: i.json.category_group, categories: i.json.categories } }));

// Aggregate pushed/assigned/per_evaluator totals from all HTTP: Push + HTTP: Assign responses.
// Runs once for ALL items (runOnceForAllItems mode) to produce a single roll-up item.
const pushItems = $('HTTP: Push').all();
const assignItems = $('HTTP: Assign').all();

let totalPushed = 0;
let totalAssigned = 0;
const perEvaluator = {};
const byCategory = {};
let hasError = false;

for (const item of pushItems) {
  const j = item.json || {};
  // Detect failure: missing ok:true or explicit error field
  if (j.ok !== true || j.error) hasError = true;
  totalPushed += (j.pushed || 0);
  const cat = j.category || '?';
  if (!byCategory[cat]) byCategory[cat] = { pushed: 0, assigned: 0 };
  byCategory[cat].pushed += (j.pushed || 0);
}

for (const item of assignItems) {
  const j = item.json || {};
  // Detect failure: missing ok:true or explicit error field
  if (j.ok !== true || j.error) hasError = true;
  totalAssigned += (j.assigned || 0);
  const cat = j.category || '?';
  if (!byCategory[cat]) byCategory[cat] = { pushed: 0, assigned: 0 };
  byCategory[cat].assigned += (j.assigned || 0);
  // per_evaluator map from each assign response
  for (const [ev, count] of Object.entries(j.per_evaluator || {})) {
    perEvaluator[ev] = (perEvaluator[ev] || 0) + count;
  }
}

const now = new Date().toLocaleString('vi-VN', { timeZone: 'Asia/Ho_Chi_Minh' });
const catLines = Object.entries(byCategory)
  .map(([c, v]) => `  ${c}: pushed=${v.pushed} assigned=${v.assigned}`)
  .join('\n');
const evLines = Object.entries(perEvaluator)
  .map(([e, v]) => `  ${e}: ${v}`)
  .join('\n');

const note = `[${now}] db-push-assign (dryRun=true)\nTotal pushed: ${totalPushed} | assigned: ${totalAssigned}\nBy category:\n${catLines || '  (none)'}\nBy evaluator:\n${evLines || '  (none)'}`;

const status = hasError ? 'error' : 'success';
return [{ json: { name: 'db-push-assign', status, note } }];

